#!/usr/bin/env python3n"""book-canvas-server.py - Infinite Canvas Server"""nnimport jsonnimport uuidnimport loggingnfrom http.server import HTTPServer, SimpleHTTPRequestHandlernfrom pathlib import Pathnn# ConfigurationnHTTP_PORT = 3001nBASE_DIR = Path(__file__).parentnSTATIC_DIR = BASE_DIR / "ui" / "public"nn# Setup loggingnlogging.basicConfig(n    level=logging.INFO,n    format='%(asctime)s %(message)s'n)nlogger = logging.getLogger('book-canvas')nn# Simple storagenclass Storage:n    def __init__(self):n        self._sessions = {}n    n    def create_session(self, user_id="anonymous"):n        session_id = f"session_{uuid.uuid().hex}"n        self._sessions[session_id] = {n            "id": session_id,n            "userId": user_id,n            "createdAt": "now",n            "canvas": {"viewport": {"x": 0, "y": 0, "zoom": 1}, "nodes": []}n        }n        return self._sessions[session_id]nnstorage = Storage()nn# HTTP Handlernclass Handler(SimpleHTTPRequestHandler):n    def __init__(self, *args, **kwargs):n        super().__init__(*args, directory=str(STATIC_DIR), **kwargs)n    n    def _json(self, status=200, data=None):n        self.send_response(status)n        self.send_header("Content-Type", "application/json")n        self.send_header("Access-Control-Allow-Origin", "*")n        self.end_headers()n        self.wfile.write(json.dumps(data or {}).encode())n    n    def do_GET(self):n        if self.path == "/api/status":n            self._json(200, {"status": "running", "sessions": len(storage._sessions)})n        elif self.path == "/api/sessions":n            self._json(200, [{"id": s["id"]} for s in storage._sessions.values()])n        else:n            return super().do_GET()n    n    def do_POST(self):n        if self.path == "/api/session/create":n            s = storage.create_session()n            self._json(201, {"sessionId": s["id"]})n        else:n            self._json(404)nn# Mainndef main():n    logger.info(f"Starting server on http://localhost:{HTTP_PORT}")n    server = HTTPServer(("localhost", HTTP_PORT), Handler)n    logger.info("Server running!")n    server.serve_forever()nnif __name__ == "__main__":n    main()